// ===== EDIT THIS: YOUR 10 CLIENTS =====
const clients = [
  {
    id: 'client1',
    name: 'Client 1 Business Name',
    locationId: 'GHL_LOCATION_ID',
    email: 'client@email.com',
    phone: '+15081234567',
    language: 'en',
    siteUrl: 'https://clientwebsite.com',  // for Google Search Console
    gaPropertyId: '123456789'               // GA4 Property ID
  },
  // Copy and paste for each client:
  // {
  //   id: 'client2',
  //   name: 'Business Name',
  //   locationId: 'GHL_LOCATION_ID',
  //   email: 'email@email.com',
  //   phone: '+1XXXXXXXXXX',
  //   language: 'en',
  //   siteUrl: 'https://website.com',
  //   gaPropertyId: 'GA4_PROPERTY_ID'
  // },
];

return clients.map(c => ({ json: c }));

// Calculate date range: last 30 days
const now = new Date();
const start = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
return [{ json: {
  ...$json,
  startDate: start.toISOString().split('T')[0],
  endDate: now.toISOString().split('T')[0],
  monthName: now.toLocaleString('en-US', { month: 'long', year: 'numeric' })
}}];

// Merge ALL data sources into one report object
const client = $('Set Date Range').item.json;

// Google Search Console
const gscQueries = $('Google Search Console — Top Queries').item.json;
const gscTotals = $('Google Search Console — Totals').item.json;
const topQueries = (gscQueries.rows || []).slice(0, 5).map(r => r.keys[0] + ' (' + r.clicks + ' clicks)');
const totalImpressions = gscTotals.rows ? gscTotals.rows.reduce((s, r) => s + r.impressions, 0) : 0;
const totalClicks = gscTotals.rows ? gscTotals.rows.reduce((s, r) => s + r.clicks, 0) : 0;
const avgCTR = totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100).toFixed(1) : 0;
const avgPosition = gscTotals.rows ? (gscTotals.rows.reduce((s, r) => s + r.position, 0) / gscTotals.rows.length).toFixed(1) : 0;

// Google Analytics
const ga = $('Google Analytics — Traffic & Channels').item.json;
const gaRows = ga.rows || [];
let totalSessions = 0, totalUsers = 0, totalPageviews = 0;
const channels = {};
gaRows.forEach(r => {
  const channel = r.dimensionValues[0].value;
  const sessions = parseInt(r.metricValues[0].value) || 0;
  totalSessions += sessions;
  totalUsers += parseInt(r.metricValues[1].value) || 0;
  totalPageviews += parseInt(r.metricValues[3].value) || 0;
  channels[channel] = sessions;
});

// GHL Contacts
const contacts = $('GHL — New Leads').item.json.contacts || [];
const sources = {};
contacts.forEach(c => {
  const src = c.source || c.tags?.[0] || 'Direct';
  sources[src] = (sources[src] || 0) + 1;
});

// GHL Pipeline
const opps = ($('GHL — Pipeline').item.json.opportunities || []);
let won = 0, lost = 0, open = 0, value = 0;
opps.forEach(o => {
  if (o.status === 'won') { won++; value += (o.monetaryValue || 0); }
  else if (o.status === 'lost') lost++;
  else open++;
});

return [{ json: {
  ...client,
  // GSC
  impressions: totalImpressions,
  clicks: totalClicks,
  ctr: avgCTR,
  avgPosition: avgPosition,
  topQueries: topQueries.join(', ') || 'No data',
  // GA4
  sessions: totalSessions,
  users: totalUsers,
  pageviews: totalPageviews,
  trafficChannels: JSON.stringify(channels),
  // GHL
  totalLeads: contacts.length,
  leadSources: JSON.stringify(sources),
  totalOpps: opps.length,
  oppsWon: won,
  oppsLost: lost,
  oppsOpen: open,
  pipelineValue: value
}}];

